    hdrs = {str(c.value).strip(): c.column - 1 for c in sh[1] if c.value}
    for r in sh.iter_rows(min_row=2, values_only=True):
        if r and str(r[0]).strip() == 'CASE-2026-00413':
            return list(r), hdrs, None
    return None, hdrs, 'CASE-2026-00413 not found in appeals_log_master.xlsx'

def _g(row, hdrs, col):
    i = hdrs.get(col)
    return str(row[i]).strip() if i is not None and i < len(row) and row[i] is not None else ''

def verify(workspace_path, external_services_path=None):
