import json
from pathlib import Path as _P

def _slack(ext):
    if ext:
        p = _P(ext) / 'slack_data.json'
        if p.exists():
            return json.loads(p.read_text()), None
    return None, 'slack_data.json not found in external_services_path'

def _msgs_in(data, channel_name):
    for cid, ch in data.get('channels', {}).items():
        if ch.get('name', '').lower() == channel_name.lower():
            return data.get('messages', {}).get(cid, [])
    return []

def _is_public(data, cid):
    ch = data.get('channels', {}).get(cid, {})
    return ch.get('is_channel', False) and not ch.get('is_private', False) and not ch.get('is_im', False)

def _dm_msgs_for(data, username):
    out = []
    for cid, ch in data.get('channels', {}).items():
        name = ch.get('name', '').lower()
        members = [str(m).lower() for m in ch.get('members', [])]
        is_dm = ch.get('is_im', False) or ch.get('is_mpim', False) or not ch.get('is_channel', True)
        if is_dm and (username.lower() in name or any(username.lower() in m for m in members)):
            out.extend(data.get('messages', {}).get(cid, []))
    return out

def verify(workspace_path, external_services_path=None):
    data, err = _slack(external_services_path)
    if err:
        return {'pass': False, 'score': 0.0, 'feedback': err}
    case_id = 'CASE-2026-00413'
    failures = []
    dm_msgs = _dm_msgs_for(data, 'aontario')
    case_dms = [str(m.get('text', '')) for m in dm_msgs if case_id in str(m.get('text', ''))]
    if not case_dms:
        failures.append('No DM to @aontario found containing CASE-2026-00413')
    else:
        combined = ' '.join(case_dms).lower()
        for field in ['clinical routing', 'case #', 'type', 'service classification',
                      'standard of review', 'deadline', 'parity flag']:
            if field not in combined:
                failures.append(f'B-1 DM missing required field: "{field}"')
    urgent_msgs = _msgs_in(data, 'appeals-urgent')
    dw_uid = next((uid for uid, u in data.get('users', {}).items()
                   if u.get('name', '').lower() == 'dwhitfield'), None)
    def _tags_dwhitfield(text):
        t = str(text).lower()
        return 'dwhitfield' in t or (dw_uid is not None and f'<@{dw_uid.lower()}>' in t)
    if not any(case_id in str(m.get('text', '')) and _tags_dwhitfield(m.get('text', ''))
               for m in urgent_msgs):
        failures.append('No post in #appeals-urgent with CASE-2026-00413 tagging @dwhitfield')
    if failures:
        return {'pass': False, 'score': max(0, (9 - len(failures)) / 9),
                'feedback': str(failures)}
    return {'pass': True, 'score': 1.0,
            'feedback': 'B-1 DM to @aontario has all required fields; #appeals-urgent post found'}

