import re

NARRATIVE_FIELDS = [
    'Basis for Standing',
    'Denial Reasoning Summary',
    'Clinical Finding Summary',
    'Flag Indicator Summary',
    'Parity Finding Summary',
]
# Rationale appears twice (Standard of Review and Decision sections); check both
RATIONALE_LABEL = 'Rationale'

YESNO_FIELDS = [
    'Standing Confirmed',
    'Parity Flag Raised at Intake',
    'Parity Review Committee Consulted',
    'Parity Committee Concurrence Received',
    'Within Coordinator Authority',
    'Supervisor Approval Required',
    'Appeal Mill Flag',
]

DATE_FIELDS = [
    'Date of Receipt',
    'Decision Deadline',
]

def verify(workspace_path, external_services_path=None):
    paras, text, err = _paras(workspace_path)
    if err:
        return {'pass': False, 'score': 0.0, 'feedback': err}
    failures = []
    def f(label): return _field(text, label)

    # Narrative fields must be PENDING
    for label in NARRATIVE_FIELDS:
        val = f(label)
        if val is None:
            failures.append(f'{label}: field not found')
        elif val.upper() != 'PENDING':
            failures.append(f'{label}: expected PENDING, got "{val[:60]}"')
    # Rationale — may appear multiple times; all occurrences must be PENDING
    for m in re.finditer(r'Rationale\s*:\s*(.+)', text, re.IGNORECASE):
        val = m.group(1).strip()
        if val.upper() != 'PENDING':
            failures.append(f'Rationale: expected PENDING, got "{val[:60]}"')

    # YES/NO fields must be exactly YES or NO in capitals
    for label in YESNO_FIELDS:
        val = f(label)
        if val is None:
            continue  # absence caught by section headings verifier
        if val not in ('YES', 'NO', 'PENDING', 'N/A'):
            failures.append(f'{label}: YES/NO field must be YES, NO, PENDING, or N/A — got "{val}"')

    # Date fields must match MM/DD/YYYY
    date_re = re.compile(r'^\d{2}/\d{2}/\d{4}')
    for label in DATE_FIELDS:
        val = f(label)
        if val is None:
            failures.append(f'{label}: field not found')
        elif not date_re.match(val):
            failures.append(f'{label}: expected MM/DD/YYYY, got "{val}"')

    total = len(NARRATIVE_FIELDS) + 2 + len(YESNO_FIELDS) + len(DATE_FIELDS)
    if failures:
        return {'pass': False, 'score': max(0, (total - len(failures)) / total),
                'feedback': f'Memo format errors: {failures}'}
    return {'pass': True, 'score': 1.0,
            'feedback': 'All narrative fields PENDING, YES/NO fields correctly capitalized, dates in MM/DD/YYYY'}
